val packingList = searchFiles(query = "hawaii vacation plans").map { files =>
  if (files.isEmpty) {
    "File 'hawaii vacation plans' not found."
  } else {
    val file = files.head
    val content = file.content
    prompt(s"Based on the following vacation plan, create a packing list for a trip to Hawaii:\n$content")
  }
}

val fileId = packingList.map(list => createFile(filename = "hawaii-packing-list.docx", content = list).id)

fileId.map(id => shareFile(fileId = id, email = "john.doe@gmail.com", permission = SharingPermission.Read))

